import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import './CampaignDetail.css';

const CampaignDetail = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user, isAuthenticated } = useAuth();

  const [campaign, setCampaign] = useState(null);
  const [donations, setDonations] = useState([]);
  const [loading, setLoading] = useState(true);
  const [donationsLoading, setDonationsLoading] = useState(true);
  const [error, setError] = useState('');
  const [donateAmount, setDonateAmount] = useState('');
  const [donateError, setDonateError] = useState('');
  const [donateLoading, setDonateLoading] = useState(false);
  const [donateSuccess, setDonateSuccess] = useState('');

  const PRESET_AMOUNTS = [100, 500, 1000, 2500, 5000];

  const fetchCampaign = useCallback(async () => {
    try {
      setLoading(true);
      setError('');
      const { data } = await axios.get(`/api/campaigns/${id}`);
      setCampaign(data.campaign);
    } catch (err) {
      if (err.response?.status === 404) {
        setError('Campaign not found.');
      } else {
        setError(err.response?.data?.message || 'Failed to load campaign.');
      }
    } finally {
      setLoading(false);
    }
  }, [id]);

  const fetchDonations = useCallback(async () => {
    try {
      setDonationsLoading(true);
      const { data } = await axios.get(`/api/donations/${id}`);
      setDonations(data.donations);
    } catch (err) {
      console.error('Failed to load donations:', err.message);
    } finally {
      setDonationsLoading(false);
    }
  }, [id]);

  useEffect(() => {
    fetchCampaign();
    fetchDonations();
  }, [fetchCampaign, fetchDonations]);

  const handleDonate = async () => {
    if (!isAuthenticated()) {
      navigate('/login');
      return;
    }

    const amount = Number(donateAmount);
    if (!donateAmount || isNaN(amount) || amount < 1) {
      setDonateError('Please enter a valid donation amount (minimum ₹1).');
      return;
    }

    if (amount > 500000) {
      setDonateError('Maximum donation amount is ₹5,00,000 per transaction.');
      return;
    }

    try {
      setDonateLoading(true);
      setDonateError('');
      setDonateSuccess('');

      // Step 1: Create Razorpay order from backend
      const { data: orderData } = await axios.post('/api/donations/create-order', {
        amount,
        campaignId: id
      });

      // Step 2: Open Razorpay checkout popup
      const razorpayKey = process.env.REACT_APP_RAZORPAY_KEY || orderData.key;

      const options = {
        key: razorpayKey,
        amount: orderData.amount, // already in paise
        currency: orderData.currency,
        name: 'FundIt',
        description: `Donation to: ${campaign.title}`,
        order_id: orderData.orderId,
        prefill: {
          name: user.name,
          email: user.email
        },
        theme: {
          color: '#7c3aed'
        },
        handler: async function (response) {
          // Step 3: Record successful payment in DB
          try {
            await axios.post('/api/donations/record', {
              campaignId: id,
              amount,
              paymentId: response.razorpay_payment_id,
              orderId: response.razorpay_order_id
            });

            setDonateSuccess(
              `🎉 Thank you for your generous donation of ₹${amount.toLocaleString('en-IN')}! Your support makes a real difference.`
            );
            setDonateAmount('');

            // Refresh campaign data and donations
            await fetchCampaign();
            await fetchDonations();
          } catch (recordErr) {
            setDonateError(
              'Payment was successful but failed to record. Please contact support with payment ID: ' +
              response.razorpay_payment_id
            );
          } finally {
            setDonateLoading(false);
          }
        },
        modal: {
          ondismiss: function () {
            setDonateLoading(false);
            setDonateError('Payment was cancelled. You were not charged.');
          }
        }
      };

      if (typeof window.Razorpay === 'undefined') {
        throw new Error('Razorpay checkout script failed to load. Please refresh the page and try again.');
      }

      const rzp = new window.Razorpay(options);

      rzp.on('payment.failed', function (response) {
        setDonateLoading(false);
        setDonateError(
          `Payment failed: ${response.error.description || 'Unknown error'}. Please try again.`
        );
      });

      rzp.open();
    } catch (err) {
      setDonateLoading(false);
      setDonateError(err.response?.data?.message || err.message || 'Failed to initiate payment. Please try again.');
    }
  };

  if (loading) {
    return (
      <div className="loading-state">
        <div className="spinner spinner-lg"></div>
        <p>Loading campaign...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="container" style={{ paddingTop: '4rem', textAlign: 'center' }}>
        <div className="alert alert-error" id="campaign-load-error" style={{ maxWidth: '500px', margin: '0 auto 2rem' }}>
          <span>⚠️</span>
          <p>{error}</p>
        </div>
        <Link to="/" className="btn btn-primary" id="btn-back-home">← Back to Campaigns</Link>
      </div>
    );
  }

  const progress = Math.min(Math.round((campaign.raised / campaign.goal) * 100), 100);
  const remaining = Math.max(campaign.goal - campaign.raised, 0);
  const isGoalReached = campaign.raised >= campaign.goal;
  const createdDate = new Date(campaign.createdAt).toLocaleDateString('en-IN', {
    year: 'numeric', month: 'long', day: 'numeric'
  });

  return (
    <div className="campaign-detail-page">
      <div className="container">
        <div className="detail-layout">
          {/* Main Content */}
          <div className="detail-main">
            {/* Breadcrumb */}
            <div className="breadcrumb" id="detail-breadcrumb">
              <Link to="/" id="breadcrumb-home">Campaigns</Link>
              <span> / </span>
              <span className="badge badge-primary">{campaign.category}</span>
            </div>

            {/* Campaign Image */}
            <div className="detail-image-wrapper" id="campaign-detail-image">
              {campaign.imageUrl ? (
                <img
                  src={campaign.imageUrl}
                  alt={campaign.title}
                  className="detail-image"
                  onError={(e) => {
                    e.target.onerror = null;
                    e.target.src = `https://picsum.photos/seed/${id}/900/450`;
                  }}
                />
              ) : (
                <div className="detail-image-placeholder">
                  {campaign.category === 'Medical' ? '🏥' :
                   campaign.category === 'Education' ? '📚' :
                   campaign.category === 'Social' ? '🤝' :
                   campaign.category === 'Environment' ? '🌿' :
                   campaign.category === 'Animal Welfare' ? '🐾' :
                   campaign.category === 'Disaster Relief' ? '⛑️' : '💡'}
                </div>
              )}
              {isGoalReached && (
                <div className="goal-reached-banner" id="goal-reached-banner">
                  🎉 Goal Reached!
                </div>
              )}
            </div>

            {/* Campaign Info */}
            <div className="detail-info card" id="campaign-info-card">
              <h1 className="detail-title" id="campaign-detail-title">{campaign.title}</h1>

              <div className="detail-meta" id="campaign-meta">
                <span className="meta-item">
                  👤 By <strong>{campaign.creator?.name || 'Anonymous'}</strong>
                </span>
                <span className="meta-divider">·</span>
                <span className="meta-item">📅 {createdDate}</span>
                <span className="meta-divider">·</span>
                <span className="badge badge-primary">{campaign.category}</span>
              </div>

              <div className="divider"></div>

              <div className="detail-description" id="campaign-description-text">
                {campaign.description.split('\n').map((para, i) => (
                  <p key={i}>{para}</p>
                ))}
              </div>
            </div>

            {/* Donors List */}
            <div className="card donations-card" id="donations-section">
              <h2 style={{ fontSize: '1.15rem', marginBottom: '1.25rem' }}>
                💜 {donations.length} Supporter{donations.length !== 1 ? 's' : ''}
              </h2>

              {donationsLoading ? (
                <div className="loading-state" style={{ padding: '2rem 0' }}>
                  <div className="spinner"></div>
                </div>
              ) : donations.length === 0 ? (
                <p style={{ color: 'var(--text-muted)', textAlign: 'center', padding: '1.5rem 0' }}>
                  Be the first to support this campaign! 🌟
                </p>
              ) : (
                <div className="donors-list" id="donors-list">
                  {donations.map((donation) => (
                    <div key={donation._id} className="donor-item">
                      <div className="donor-avatar">
                        {donation.donor?.name?.charAt(0).toUpperCase() || '?'}
                      </div>
                      <div className="donor-info">
                        <span className="donor-name">{donation.donor?.name || 'Anonymous'}</span>
                        <span className="donor-time">
                          {new Date(donation.createdAt).toLocaleDateString('en-IN', {
                            month: 'short', day: 'numeric', year: 'numeric'
                          })}
                        </span>
                      </div>
                      <span className="donor-amount">
                        ₹{donation.amount.toLocaleString('en-IN')}
                      </span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>

          {/* Sticky Sidebar */}
          <div className="detail-sidebar">
            <div className="donate-card card" id="donation-card">
              {/* Progress Info */}
              <div className="progress-section" id="campaign-progress-section">
                <div className="raised-display" id="raised-display">
                  <span className="raised-big">₹{campaign.raised.toLocaleString('en-IN')}</span>
                  <span className="raised-label">raised of ₹{campaign.goal.toLocaleString('en-IN')} goal</span>
                </div>

                <div className="progress-bar-wrapper" style={{ height: '12px', margin: '1rem 0' }}>
                  <div
                    className="progress-bar-fill"
                    style={{ width: `${progress}%` }}
                    id="campaign-progress-bar"
                    role="progressbar"
                    aria-valuenow={progress}
                    aria-valuemin="0"
                    aria-valuemax="100"
                  ></div>
                </div>

                <div className="progress-stats" id="progress-stats">
                  <div className="progress-stat-item">
                    <strong className="gradient-text">{progress}%</strong>
                    <span>funded</span>
                  </div>
                  <div className="progress-stat-item">
                    <strong>{donations.length}</strong>
                    <span>donors</span>
                  </div>
                  <div className="progress-stat-item">
                    <strong>₹{remaining.toLocaleString('en-IN')}</strong>
                    <span>remaining</span>
                  </div>
                </div>
              </div>

              <div className="divider"></div>

              {/* Donate Section */}
              {donateSuccess && (
                <div className="alert alert-success" id="donate-success-alert" role="alert">
                  <span>🎉</span>
                  <p>{donateSuccess}</p>
                </div>
              )}

              {donateError && (
                <div className="alert alert-error" id="donate-error-alert" role="alert">
                  <span>⚠️</span>
                  <p>{donateError}</p>
                </div>
              )}

              {!isAuthenticated() ? (
                <div style={{ textAlign: 'center' }}>
                  <p style={{ color: 'var(--text-secondary)', marginBottom: '1rem', fontSize: '0.9rem' }}>
                    Log in to support this campaign
                  </p>
                  <Link to="/login" className="btn btn-primary btn-full" id="btn-login-to-donate">
                    Log in to Donate
                  </Link>
                </div>
              ) : (
                <div className="donate-form" id="donate-form">
                  <h3 style={{ marginBottom: '1rem' }}>Make a Donation</h3>

                  {/* Preset amounts */}
                  <div className="preset-amounts" id="preset-amounts">
                    {PRESET_AMOUNTS.map((amt) => (
                      <button
                        key={amt}
                        id={`preset-amount-${amt}`}
                        className={`preset-btn ${donateAmount === String(amt) ? 'preset-btn-active' : ''}`}
                        onClick={() => {
                          setDonateAmount(String(amt));
                          setDonateError('');
                          setDonateSuccess('');
                        }}
                        type="button"
                      >
                        ₹{amt.toLocaleString('en-IN')}
                      </button>
                    ))}
                  </div>

                  <div className="form-group" style={{ marginBottom: '1rem' }}>
                    <label className="form-label" htmlFor="donate-amount-input">Or enter custom amount (₹)</label>
                    <input
                      id="donate-amount-input"
                      type="number"
                      className="form-input"
                      placeholder="e.g., 750"
                      value={donateAmount}
                      onChange={(e) => {
                        setDonateAmount(e.target.value);
                        setDonateError('');
                        setDonateSuccess('');
                      }}
                      min={1}
                      max={500000}
                    />
                  </div>

                  {donateAmount && Number(donateAmount) > 0 && (
                    <div className="donation-summary" id="donation-summary">
                      <span>You are donating</span>
                      <strong className="gradient-text">₹{Number(donateAmount).toLocaleString('en-IN')}</strong>
                    </div>
                  )}

                  <button
                    className="btn btn-primary btn-full btn-lg"
                    onClick={handleDonate}
                    disabled={donateLoading || !donateAmount}
                    id="btn-donate-now"
                    style={{ marginTop: '0.75rem' }}
                  >
                    {donateLoading ? (
                      <>
                        <span className="spinner"></span>
                        Processing...
                      </>
                    ) : (
                      '💜 Donate Now via Razorpay'
                    )}
                  </button>

                  <p className="secure-notice" id="secure-notice">
                    🔒 100% secure payments powered by Razorpay
                  </p>
                </div>
              )}
            </div>

            {/* Share Card */}
            <div className="card share-card" id="share-card">
              <h3 style={{ marginBottom: '0.75rem', fontSize: '0.95rem' }}>📣 Share this Campaign</h3>
              <p style={{ color: 'var(--text-muted)', fontSize: '0.85rem', marginBottom: '1rem' }}>
                Help reach more people by sharing on social media.
              </p>
              <div className="share-buttons">
                <button
                  className="share-btn share-whatsapp"
                  id="btn-share-whatsapp"
                  onClick={() => window.open(`https://wa.me/?text=${encodeURIComponent(`Support this cause: ${campaign.title} - ${window.location.href}`)}`)}
                >
                  WhatsApp
                </button>
                <button
                  className="share-btn share-twitter"
                  id="btn-share-twitter"
                  onClick={() => window.open(`https://twitter.com/intent/tweet?text=${encodeURIComponent(`Support "${campaign.title}" on FundIt`)}&url=${encodeURIComponent(window.location.href)}`)}
                >
                  Twitter
                </button>
                <button
                  className="share-btn share-copy"
                  id="btn-copy-link"
                  onClick={() => {
                    navigator.clipboard.writeText(window.location.href);
                    alert('Link copied to clipboard!');
                  }}
                >
                  Copy Link
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CampaignDetail;
